function bar(v){return`<div class='meter'><div class='fill' style='width:${Math.max(0,Math.min(140,N(v)))}%'></div></div>`}
function calcCard(r,k){const v=metricData(r,k),t=N(v.target),a=N(v.actual),idx=t?a/t*100:N(v.index),full=Math.max(t-a,0),d=Math.max(daysLeft(),1),pv=pctVal(k),has=String(pv??'').trim()!=='',pn=N(pv),goal=has?t*pn/100:0,need=has?Math.max(goal-a,0):0,per=has?need/d:0;return`<div class='kpi calcKpi'><span>${metric(k)}</span><div class='kv'><em>เป้าหมาย</em><b>${M(t)}</b></div><div class='kv'><em>ทำแล้ว</em><b>${M(a)}</b><i>${P(idx)}</i></div><div class='kv'><em>ขาด</em><b>${M(full)}</b></div><label class='pctBox'><input data-pct='${E(k)}' inputmode='decimal' type='number' min='0' max='150' step='1' value='${E(pv)}' placeholder='ใส่ %'><strong>%</strong></label><small>${has?'เป้า '+P(pn)+' = '+M(goal)+' · ต้องทำ '+M(need)+' · วันละ '+M(per)+' / '+M(d)+' วัน':'กรอก % เพื่อคำนวณเป้าและยอดที่ต้องทำ'}</small></div>`}
function workCard(){const m=data?.meta||{},d=daysLeft(),wd=N(m.workdayNo),tw=N(m.totalWorkdays);return`<div class='kpi calcKpi workKpi'><span>วันทำงานที่ใช้หาร</span><div class='kv'><em>วันทำงานเหลือ</em><b>${M(d)}</b></div><div class='kv'><em>WD ปัจจุบัน</em><b>${wd?M(wd):'-'}</b><i>${tw?'จาก '+M(tw):''}</i></div><small>ทุกช่องที่กรอก % ใช้ ${M(Math.max(d,1))} วันเป็นตัวหาร ถ้าเหลือ 0 จะกันหารด้วย 1 เพื่อไม่ให้คำนวณพัง</small></div>`}
function kpis(r){return`<div class='kpis calcGrid'>${calcCard(r,'sales')}${calcCard(r,'giv')}${calcCard(r,'moq')}${calcCard(r,'dc1')}${calcCard(r,'bills')}${calcCard(r,'dc2')}${workCard()}${calcCard(r,'dc3')}</div>`}
