function sum(rows,code){const out={code,name:code};K().forEach(k=>{out[k]=aggregate(rows,k)});return out}
function row(r,i,k,next){const v=metricData(r,k);return`<button class='row' data-mode='${E(next.mode)}' data-cat='${E(next.cat||'')}' data-ads='${E(next.ads||'')}' data-ps='${E(next.ps||'')}'><div class='no'>${i+1}</div><div class='rowMain'><div class='rowHead'><b>${label(r)}</b></div><span class='rowSub'>Target ${M(v.target)} / Actual ${M(v.actual)} / ${remain(v)}</span>${bar(v.index)}</div><div class='right'>${P(v.index)}</div></button>`}
