function screenAds(){const rows=data.ads||[];const score=r=>{const used=K().filter(k=>N(metricData(r,k)?.index)>0);return used.length?used.reduce((s,k)=>s+N(metricData(r,k)?.index),0)/used.length:0};return nav()+hero('ADS ทั้ง 4','จัดตาม Seller Report',sum(data.ps,'ADS'))+`<section class='panel'><h3>ADS Rank all target</h3><div class='rank'>${[...rows].sort((a,b)=>score(b)-score(a)).map((r,i)=>adsRankRow(r,i,score(r))).join('')}</div></section>`+categories(rows,'จัดอันดับ ADS','ads')}
function screenPs(){const sel=state.ads||'AYAADS01',rows=(data.ps||[]).filter(x=>(x.ads||x.adsCode)===sel);return nav()+hero(sel+' · PS','ข้อมูลเฉพาะ ADS นี้',sum(rows,sel))+`<section class='panel'><h3>PS Rank</h3>${rank([...rows].sort((a,b)=>N(metricData(b,'sales')?.index)-N(metricData(a,'sales')?.index)),'sales','ps')}</section>`+categories(rows,'Seller Report Detail','ps')}
function screenPerson(){const p=(data.ps||[]).find(x=>(x.ps||x.psCode)===state.ps)||(data.ps||[])[0];return nav()+hero(label(p),'รายละเอียดตามชีท',p)+`<section class='panel'><h3>Raw tab</h3><div class='grid'>${K().map(k=>{const v=metricData(p,k);return`<div class='card'><b>${metric(k)}</b><span>Target ${M(v.target)} / Actual ${M(v.actual)}<br>${remain(v)}</span>${bar(v.index)}<small>${P(v.index)}</small></div>`}).join('')}</div></section>`}
function avgMetric(list,k){let t=0,a=0,ix=0,c=0;list.forEach(r=>{const v=metricData(r,k);t+=N(v.target);a+=N(v.actual);ix+=N(v.index);c++});return{target:c?t/c:0,actual:c?a/c:0,index:c?ix/c:0}}function avgPack(packs){packs=packs.map(hydratePack);const one=(set,key)=>{const first=packs[0]?.[set]||[];return first.map(b=>{const id=b[key]||b.code,rows=packs.map(p=>(p[set]||[]).find(x=>(x[key]||x.code)===id)).filter(Boolean),r={...b};K().forEach(k=>r[k]=avgMetric(rows,k));return r})};const ds={...(packs[0]?.ds||{})};K().forEach(k=>ds[k]=avgMetric(packs.map(p=>p.ds).filter(Boolean),k));return hydratePack({ds,ads:one('ads','ads'),ps:one('ps','ps')})}
function historyRows(rows,cur){const m=new Map();rows.forEach(x=>{const key=x.reportDate||x.reportKey||x.path;if(!key)return;if(x.path===cur.comparePath||x.path===cur.dataPath||x.reportKey===cur.reportKey)return;if(x.reportDate&&cur.reportDate&&x.reportDate===cur.reportDate)return;if(!m.has(key))m.set(key,x)});let out=[...m.values()];if(cur.reportDate)out=out.filter(x=>!x.reportDate||String(x.reportDate)<String(cur.reportDate));return out}
async function oldPack(kind){const hist=await fetchJson('performance/history-index.json',8000),cur=data.meta||{},older=historyRows(Array.isArray(hist)?hist.filter(x=>x.path):[],cur);if(kind==='same'){const pick=older.find(x=>N(x.workdayNo)===N(cur.workdayNo)-12);if(!pick)throw Error('ยังไม่มีข้อมูลตลาดเดิมรอบก่อนในเดือนนี้');return{pick,old:hydratePack(await fetchJson(pick.path,12000))}}if(kind==='avg3'){const picks=older.slice(0,3);if(!picks.length)throw Error('ยังไม่มีข้อมูลย้อนหลังสำหรับค่าเฉลี่ย');return{pick:{reportKey:'เฉลี่ย '+picks.length+' วันล่าสุด'},old:avgPack(await Promise.all(picks.map(x=>fetchJson(x.path,12000))))}}const pick=older[0];if(!pick)throw Error('ยังไม่มีไฟล์วันทำงานก่อนหน้าให้เทียบ');return{pick:{...pick,reportKey:kind==='pace'?'Pace เป้า':pick.reportKey},old:hydratePack(await fetchJson(pick.path,12000))}}
function cmpNav(){const m=data.meta||{},wd=N(m.workdayNo),market=wd?((wd-1)%12)+1:'-',round=wd?Math.floor((wd-1)/12)+1:'-',items=[['prev','เทียบวันก่อน','ใช้ reportDate ก่อนหน้า'],['same','เทียบตลาดเดิม','ตลาด '+market+' รอบ '+round],['avg3','เฉลี่ย 3 วัน','ย้อนหลัง 3 ไฟล์'],['pace','Pace เป้า','เทียบต้องทำ/วัน']];return`<div class='muted'>เลือกรูปแบบการเทียบ</div><div class='cmpSlider'>${items.map(([k,t,d])=>`<button class='cmpCard ${state.cmp===k?'on':''}' data-mode='compare' data-cmp='${k}' data-cat='${E(state.cat||'')}' data-ads='${E(state.ads||'')}'><b>${E(t)}</b><span>${E(d)}</span></button>`).join('')}</div>`}
function pair(c,o){if(state.cmp==='pace'){const inc=Math.max(N(c?.actual)-N(o?.actual),0),p=pace(c).p;return{a:inc,b:p,d:inc-p,ix:p?inc/p*100:0}}const a=N(c?.actual),b=N(o?.actual);return{a,b,d:a-b,ix:N(c?.index)}}
function diffCard(cur,old,k,i){const cv=metricData(cur,k),ov=metricData(old,k),r=pair(cv,ov),left=state.cmp==='pace'?`เพิ่ม ${M(r.a)} / Pace ${M(r.b)}`:`ล่าสุด ${M(r.a)} / ก่อนหน้า ${M(r.b)}`;return`<button class='card cmpCatCard' data-mode='compare' data-cat='${E(k)}' data-cmp='${E(state.cmp)}'><small>#${i+1}</small><b>${metric(k)}</b><span>${left}<br>${remain(cv)}</span><strong class='diff ${r.d>=0?'up':'dn'}'>${r.d>=0?'+':''}${M(r.d)}</strong></button>`}
